patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 2d7524e8018b..2301ff2a7c82 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -1367,6 +1367,98 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
     }
   }

+  // Handle (icmp Pred V, C) & (icmp eq (V & Mask), C2)
+  // where all values satisfying (V & Mask) == C2 also satisfy Pred V, C.
+  // In this case, the first comparison is redundant.
+  const APInt *AndMask = nullptr;
+  Value *AndBase = nullptr;
+  if (IsAnd && V1 != V2 && V1 && V2 && Pred2 == ICmpInst::ICMP_EQ &&
+      match(V2, m_OneUse(m_And(m_Value(AndBase), m_NegatedPower2(AndMask)))) &&
+      AndBase == V1) {
+    // Check if C2 is aligned to the mask (C2 & ~Mask == C2)
+    if (( *C2 & ~(*AndMask)) == 0) {
+      // The range of values satisfying (V1 & Mask) == C2 is [C2, C2 + |Mask|)
+      // Check if all these values satisfy Pred1 V1, C1
+      bool Contained = false;
+      APInt MaskAbs = AndMask->abs();
+      APInt MaxVal = *C2 + MaskAbs - 1;
+      switch (Pred1) {
+      case ICmpInst::ICMP_ULT:
+        Contained = MaxVal.ult(*C1);
+        break;
+      case ICmpInst::ICMP_ULE:
+        Contained = MaxVal.ule(*C1);
+        break;
+      case ICmpInst::ICMP_SLT:
+        Contained = MaxVal.slt(*C1);
+        break;
+      case ICmpInst::ICMP_SLE:
+        Contained = MaxVal.sle(*C1);
+        break;
+      case ICmpInst::ICMP_UGT:
+        Contained = C2->ugt(*C1);
+        break;
+      case ICmpInst::ICMP_UGE:
+        Contained = C2->uge(*C1);
+        break;
+      case ICmpInst::ICMP_SGT:
+        Contained = C2->sgt(*C1);
+        break;
+      case ICmpInst::ICMP_SGE:
+        Contained = C2->sge(*C1);
+        break;
+      default:
+        break;
+      }
+      if (Contained)
+        return ICmp2;
+    }
+  }
+
+  // Handle symmetric case: (icmp eq (V & Mask), C1) & (icmp Pred V, C2)
+  AndMask = nullptr;
+  AndBase = nullptr;
+  if (IsAnd && V1 != V2 && V1 && V2 && Pred1 == ICmpInst::ICMP_EQ &&
+      match(V1, m_OneUse(m_And(m_Value(AndBase), m_NegatedPower2(AndMask)))) &&
+      AndBase == V2) {
+    if (( *C1 & ~(*AndMask)) == 0) {
+      bool Contained = false;
+      APInt MaskAbs = AndMask->abs();
+      APInt MaxVal = *C1 + MaskAbs - 1;
+      switch (Pred2) {
+      case ICmpInst::ICMP_ULT:
+        Contained = MaxVal.ult(*C2);
+        break;
+      case ICmpInst::ICMP_ULE:
+        Contained = MaxVal.ule(*C2);
+        break;
+      case ICmpInst::ICMP_SLT:
+        Contained = MaxVal.slt(*C2);
+        break;
+      case ICmpInst::ICMP_SLE:
+        Contained = MaxVal.sle(*C2);
+        break;
+      case ICmpInst::ICMP_UGT:
+        Contained = C1->ugt(*C2);
+        break;
+      case ICmpInst::ICMP_UGE:
+        Contained = C1->uge(*C2);
+        break;
+      case ICmpInst::ICMP_SGT:
+        Contained = C1->sgt(*C2);
+        break;
+      case ICmpInst::ICMP_SGE:
+        Contained = C1->sge(*C2);
+        break;
+      default:
+        break;
+      }
+      if (Contained)
+        return ICmp1;
+    }
+  }
+
+
   if (V1 != V2)
     return nullptr;

